require 'html_to_markdown'
require 'json'

RSpec.describe 'edge-cases' do
  it 'empty_html: Empty HTML document' do
    result = HtmlToMarkdown.convert('<html><head></head><body></body></html>')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'encoding_cjk_characters: CJK (Chinese, Japanese, Korean) characters are preserved' do
    result = HtmlToMarkdown.convert('<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('中文内容')
    expect(result.content.to_s).to include('日本語テキスト')
    expect(result.content.to_s).to include('한국어 텍스트')

  end

  it 'encoding_html_entities: Common HTML entities are decoded in output' do
    result = HtmlToMarkdown.convert('<p>&amp; &lt; &gt; &nbsp; &quot; &apos;</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('&')
    expect(result.content.to_s).to include('<')
    expect(result.content.to_s).to include('>')

  end

  it 'encoding_named_entities: Named HTML entities like &mdash; and &hellip; are decoded' do
    result = HtmlToMarkdown.convert('<p>Em dash&mdash;used for parenthetical remarks&mdash;is common. Ellipsis&hellip; indicates omission. Non-breaking&nbsp;space.</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('—')
    expect(result.content.to_s).to include('…')

  end

  it 'encoding_numeric_entities: Numeric HTML entities (decimal and hex) are decoded' do
    result = HtmlToMarkdown.convert('<p>Copyright: &#169; Trade: &#174; Euro: &#8364; Hex: &#x00A9;</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('©')
    expect(result.content.to_s).to include('®')
    expect(result.content.to_s).to include('€')

  end

  it 'encoding_unicode_emoji: Emoji and Unicode characters are preserved' do
    result = HtmlToMarkdown.convert('<p>Hello 🌍 World 🚀</p><p>Stars: ⭐ ✨</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('🌍')
    expect(result.content.to_s).to include('🚀')
    expect(result.content.to_s).to include('⭐')

  end

  it 'html_comments_only: Document containing only HTML comments produces empty output' do
    result = HtmlToMarkdown.convert('<!-- This is a comment --><!-- Another comment -->')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'just_whitespace_input: Input that is only whitespace characters (spaces, tabs, newlines) produces empty output' do
    result = HtmlToMarkdown.convert('   ')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'malformed_bogus_comment_triple_dash: HTML comment ending with ---> (three dashes) must not drop content that follows (issue #339)' do
    result = HtmlToMarkdown.convert("<h1>One</h1>\n<!-- /// --->\n<p>Two</p>")
    expect(result.content.to_s).to include('One')
    expect(result.content.to_s).to include('Two')

  end

  it 'malformed_deeply_nested_elements: Deeply nested elements (100 levels) are handled without stack overflow' do
    result = HtmlToMarkdown.convert('<div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><div><p>Deeply nested content</p></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div></div>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Deeply nested content')

  end

  it 'malformed_missing_block_closing_tags: Missing closing tags on block elements are auto-closed by parser' do
    result = HtmlToMarkdown.convert('<div><h1>Title<p>First paragraph<p>Second paragraph</div>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Title')
    expect(result.content.to_s).to include('First paragraph')
    expect(result.content.to_s).to include('Second paragraph')

  end

  it 'malformed_overlapping_tags: Overlapping bold/italic tags are recovered by the HTML parser without panic' do
    result = HtmlToMarkdown.convert('<p><b><i>bold and italic</b></i></p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('bold and italic')

  end

  it 'malformed_unclosed_paragraph: Unclosed <p> tag is recovered gracefully and content is preserved' do
    result = HtmlToMarkdown.convert('<p>This paragraph is never closed')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('This paragraph is never closed')

  end

  it 'script_tags_only: Document with only script tags produces empty output (scripts are stripped)' do
    result = HtmlToMarkdown.convert('<html><head><script>alert(\'xss\')</script></head><body><script>document.write(\'hello\')</script></body></html>')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'style_tags_only: Document with only style tags produces empty output (styles are stripped)' do
    result = HtmlToMarkdown.convert('<html><head><style>body { color: red; }</style></head><body><style>.foo { margin: 0; }</style></body></html>')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'visitor_custom_element_with_nesting: Visitor handles custom elements with nested content' do
    visitor = Class.new do
      def visit_custom_element(ctx, tag_name, html)
        { custom: '[CUSTOM WIDGET]' }
      end
    end.new
    result = HtmlToMarkdown.convert('<div><custom-widget data-value="123"><p>Widget content here</p><span>With nested elements</span></custom-widget></div>', visitor)
    expect(result.content.to_s).to include('[CUSTOM WIDGET]')
    expect(result.content.to_s).not_to include('Widget content here')

  end

  it 'visitor_deeply_nested_skip: Visitor skips deeply nested elements' do
    visitor = Class.new do
      def visit_mark(ctx, text)
        'skip'
      end
    end.new
    result = HtmlToMarkdown.convert('<div><p>Outer <em>emphasis <strong>with bold <mark>and highlight</mark></strong></em> text</p></div>', visitor)
    expect(result.content.to_s).to include('Outer')
    expect(result.content.to_s).to include('text')
    expect(result.content.to_s).not_to include('highlight')

  end

  it 'visitor_element_end_modification: Visitor modifies element at end after children processed' do
    visitor = Class.new do
      def visit_element_end(ctx, output)
        { custom: 'MODIFIED OUTPUT' }
      end
    end.new
    result = HtmlToMarkdown.convert('<blockquote><p>Original quote</p></blockquote>', visitor)
    expect(result.content.to_s).not_to be_empty

  end

  it 'visitor_element_start_skip_entire_subtree: Visitor skips at element_start level removes entire subtree' do
    visitor = Class.new do
      def visit_element_start(ctx)
        'skip'
      end
    end.new
    result = HtmlToMarkdown.convert('<div><h1>Title</h1><p>Content</p></div>', visitor)
    expect(result.content.to_s).not_to include('Title')
    expect(result.content.to_s).not_to include('Content')

  end

  it 'visitor_unknown_tag_preservation: Visitor preserves unknown HTML tags as raw HTML' do
    visitor = Class.new do
      def visit_custom_element(ctx, tag_name, html)
        'preserve_html'
      end
    end.new
    result = HtmlToMarkdown.convert('<article><p>Article text</p><x-custom>Custom element with content</x-custom><p>More article text</p></article>', visitor)
    expect(result.content.to_s).to include('Article text')
    expect(result.content.to_s).to include('More article text')
    expect(result.content.to_s).to include('<x-custom>')

  end

  it 'whitespace_only: Whitespace-only content' do
    result = HtmlToMarkdown.convert('<p>   </p>')
    expect(result.content.to_s.strip).to eq(''.strip)

  end

  it 'xss_onclick_handler_removed: onclick and other on* event handlers are removed from elements' do
    result = HtmlToMarkdown.convert('<p><a href="https://example.com" onclick="alert(\'xss\')">Click me</a></p><button onmouseover="steal_data()">Hover me</button>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Click me')

  end

  it 'xss_script_tag_stripped: Script tag content is stripped and does not appear in output' do
    result = HtmlToMarkdown.convert('<p>Safe content.</p><script>alert(\'xss\')</script><p>More safe content.</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Safe content')
    expect(result.content.to_s).to include('More safe content')

  end

  it 'xss_svg_nested_script_stripped: Script tags nested inside SVG are stripped' do
    result = HtmlToMarkdown.convert('<p>Before SVG.</p><svg xmlns="http://www.w3.org/2000/svg"><script>alert(\'svg-xss\')</script><text>SVG text</text></svg><p>After SVG.</p>')
    expect(result.content.to_s).not_to be_empty
    expect(result.content.to_s).to include('Before SVG')
    expect(result.content.to_s).to include('After SVG')

  end
end
